#!/bin/bash
# 'MiOS' v0.2.4 -- 37-selinux: Build-time SELinux policy fixes
# Custom per-rule modules for known Fedora Rawhide / systemd 260 denials.
set -euo pipefail

echo "[37-selinux] Applying SELinux build-time fixes..."

# ═══ Restorecon -- fix labels for all major trees ═══
if command -v restorecon &>/dev/null; then
    echo "[37-selinux] Running restorecon on /boot /etc /usr /var..."
    restorecon -R /boot /etc /usr /var 2>/dev/null || true
fi

# ═══ Semanage import -- atomic booleans + fcontexts ═══
if command -v semanage &>/dev/null; then
    echo "[37-selinux] Applying SELinux booleans and fcontexts..."
    semanage import <<'EOSEM' 2>/dev/null || true
boolean -m --on container_manage_cgroup
boolean -m --on container_use_cephfs
boolean -m --on daemons_dump_core
boolean -m --on domain_can_mmap_files
boolean -m --on virt_sandbox_use_all_caps
boolean -m --on virt_use_nfs
boolean -m --on virt_use_samba
boolean -m --on nis_enabled
fcontext -a -t boot_t '/boot/bootupd-state.json'
fcontext -a -t accountsd_var_lib_t '/usr/share/accountsservice/interfaces(/.*)?'
fcontext -a -t ceph_var_lib_t '/var/lib/ceph(/.*)?'
fcontext -a -t ceph_log_t '/var/log/ceph(/.*)?'
fcontext -a -t xdm_var_lib_t '/var/lib/gnome-remote-desktop(/.*)?'
EOSEM
    restorecon -v /boot/bootupd-state.json 2>/dev/null || true
    restorecon -R /usr/share/accountsservice 2>/dev/null || true
    restorecon -R /var/lib/gnome-remote-desktop 2>/dev/null || true
    echo "[37-selinux] [ok] Booleans and fcontexts applied"
fi

# ═══ Custom policy modules ═══
if command -v checkmodule &>/dev/null && command -v semodule_package &>/dev/null; then
    echo "[37-selinux] Building custom SELinux policy modules..."

    SELINUX_OK=0
    SELINUX_FAIL=0

    declare -A MIOS_POLICIES

    MIOS_POLICIES[bootupd]='
module mios_bootupd 1.0;
require { type boot_t; type bootupd_t; class file { read getattr open }; }
allow bootupd_t boot_t:file { read getattr open };'

    MIOS_POLICIES[accountsd]='
module mios_accountsd 1.0;
require { type accountsd_t; class lnk_file { read getattr }; }
allow accountsd_t self:lnk_file { read getattr };'

    MIOS_POLICIES[resolved]='
module mios_resolved 1.0;
require { type systemd_resolved_t; type init_var_run_t; class sock_file write; }
allow systemd_resolved_t init_var_run_t:sock_file write;'

    MIOS_POLICIES[fapolicyd]='
module mios_fapolicyd 1.0;
require { type fapolicyd_t; type xdm_var_run_t; class sock_file write; }
allow fapolicyd_t xdm_var_run_t:sock_file write;'

    MIOS_POLICIES[chcon]='
module mios_chcon 1.0;
require { type chcon_t; class capability mac_admin; }
allow chcon_t self:capability mac_admin;'

    MIOS_POLICIES[accountsd_homed]='
module mios_accountsd_homed 1.0;
require { type accountsd_t; type systemd_homed_t; class dbus send_msg; }
allow accountsd_t systemd_homed_t:dbus send_msg;
allow systemd_homed_t accountsd_t:dbus send_msg;'

    MIOS_POLICIES[accountsd_watch]='
module mios_accountsd_watch 1.0;
require { type accountsd_t; type usr_t; class dir { watch watch_reads }; }
allow accountsd_t usr_t:dir { watch watch_reads };'

    MIOS_POLICIES[fapolicyd_gdm]='
module mios_fapolicyd_gdm 1.1;
require { type fapolicyd_t; type xdm_t; class unix_stream_socket connectto; class fd use; class fifo_file write; }
allow fapolicyd_t xdm_t:unix_stream_socket connectto;
allow fapolicyd_t xdm_t:fd use;
allow fapolicyd_t xdm_t:fifo_file write;'

    MIOS_POLICIES[fapolicyd_grd]='
module mios_fapolicyd_grd 1.0;
require { type fapolicyd_t; type gnome_remote_desktop_t; class unix_stream_socket connectto; class fd use; class fifo_file write; }
allow fapolicyd_t gnome_remote_desktop_t:unix_stream_socket connectto;
allow fapolicyd_t gnome_remote_desktop_t:fd use;
allow fapolicyd_t gnome_remote_desktop_t:fifo_file write;'

    MIOS_POLICIES[portabled]='
module mios_portabled 1.0;
require { type init_t; type systemd_portabled_t; class dbus send_msg; }
allow init_t systemd_portabled_t:dbus send_msg;
allow systemd_portabled_t init_t:dbus send_msg;'

    MIOS_POLICIES[kvmfr]='
module mios_kvmfr 1.0;
require { type svirt_t; type device_t; class chr_file { open read write map getattr }; }
allow svirt_t device_t:chr_file { open read write map getattr };'

    MIOS_POLICIES[coreos_bootmount]='
module mios_coreos_bootmount 1.0;
require { type coreos_boot_mount_generator_t; type systemd_generator_unit_file_t; class dir { write add_name remove_name }; class file { create write open rename unlink }; }
allow coreos_boot_mount_generator_t systemd_generator_unit_file_t:dir { write add_name remove_name };
allow coreos_boot_mount_generator_t systemd_generator_unit_file_t:file { create write open rename unlink };'

    MIOS_POLICIES[gdm_cache]='
module mios_gdm_cache 1.0;
require { type xdm_t; type cache_home_t; class dir { add_name write create setattr }; class file { create write open getattr setattr }; }
allow xdm_t cache_home_t:dir { add_name write create setattr };
allow xdm_t cache_home_t:file { create write open getattr setattr };'

    MIOS_POLICIES[homed_varhome]='
module mios_homed_varhome 1.0;
require { type systemd_homed_t; type home_root_t; class dir { read getattr open search }; }
allow systemd_homed_t home_root_t:dir { read getattr open search };'

    MIOS_POLICIES[bootupd_state]='
module mios_bootupd_state 1.1;
require { type bootupd_t; type boot_t; class file { read open getattr lock ioctl }; class dir { read open getattr search }; }
allow bootupd_t boot_t:file { read open getattr lock ioctl };
allow bootupd_t boot_t:dir { read open getattr search };'

    MIOS_POLICIES[resolved_hook]='
module mios_resolved_hook 1.0;
require { type systemd_resolved_t; type init_t; class unix_stream_socket connectto; class sock_file write; }
allow systemd_resolved_t init_t:unix_stream_socket connectto;
allow systemd_resolved_t init_t:sock_file write;'

    MIOS_POLICIES[accountsd_malcontent]='
module mios_accountsd_malcontent 1.0;
require { type accountsd_t; type usr_t; class lnk_file { read getattr }; class file { read open getattr ioctl }; class dir { read open getattr search }; }
allow accountsd_t usr_t:lnk_file { read getattr };
allow accountsd_t usr_t:file { read open getattr ioctl };
allow accountsd_t usr_t:dir { read open getattr search };'

    MIOS_POLICIES[chcon_macadmin]='
module mios_chcon_macadmin 1.0;
require { type chcon_t; class capability2 mac_admin; }
allow chcon_t self:capability2 mac_admin;'

    MIOS_POLICIES[gdm_session_cache]='
module mios_gdm_session_cache 1.0;
require { type xdm_t; type cache_home_t; class dir { add_name write create read open getattr search setattr }; class file { create write read open getattr setattr }; }
allow xdm_t cache_home_t:dir { add_name write create read open getattr search setattr };
allow xdm_t cache_home_t:file { create write read open getattr setattr };'

    mkdir -p /usr/share/selinux/packages/mios

    for name in "${!MIOS_POLICIES[@]}"; do
        echo "${MIOS_POLICIES[$name]}" > "/tmp/mios_${name}.te"
        if checkmodule -M -m -o "/tmp/mios_${name}.mod" "/tmp/mios_${name}.te" 2>/dev/null && \
           semodule_package -o "/tmp/mios_${name}.pp" -m "/tmp/mios_${name}.mod" 2>/dev/null; then
            install -m 0644 "/tmp/mios_${name}.pp" "/usr/share/selinux/packages/mios/mios_${name}.pp"
            echo "[37-selinux] mios_${name}: Staged"
            SELINUX_OK=$((SELINUX_OK + 1))
        else
            echo "[37-selinux] mios_${name}: SKIPPED (type missing in current policy)"
            SELINUX_FAIL=$((SELINUX_FAIL + 1))
        fi
        rm -f "/tmp/mios_${name}".{te,mod,pp}
    done

    echo "[37-selinux] ${SELINUX_OK} policies staged in /usr/share/selinux/packages/mios/, ${SELINUX_FAIL} skipped"
fi

# ─── Persistent SELinux booleans applied at first boot ─────────────────────
# usr/libexec/mios/selinux-init reads booleans.conf next to the staged .pp
# modules and applies each entry via 'setsebool -P'. semanage is typically
# inoperative inside an OCI build (no running policy / read-only contexts),
# so booleans MUST be applied at runtime; this file is the manifest the
# runtime service consults.
#
# container_use_devices=on  -- required by 35-gpu-passthrough.sh / GPU
#   container CDI flow (NVIDIA, ROCm, Intel xe). Without it, the first
#   GPU container start is denied by SELinux on enforcing hosts.
mkdir -p /usr/share/selinux/packages/mios
cat > /usr/share/selinux/packages/mios/booleans.conf <<'EOBOOL'
container_use_devices=on
EOBOOL
echo "[37-selinux] booleans.conf staged for runtime selinux-init"

echo "[37-selinux] SELinux configuration complete."

#!/usr/bin/env python3
# 'MiOS' v0.2.4 -- Bootc kargs.d validator
"""
validate-kargs.py -- 'MiOS' kargs.d schema validator.

Checks every *.toml in:
  kargs.d/                              (repo root drop-ins)
  usr/lib/bootc/kargs.d/  (image-baked drop-ins)

Schema rules (bootc-dev/bootc authoritative):
  - Top-level key `kargs` (required) must be a list of strings.
  - Top-level key `match-architectures` (optional) must be a list of strings.
  - NO other top-level keys.
  - NO [section] table headers anywhere in the file.
  - Each kargs entry must be a single string (not space-joined multi-arg).
  - Keys with "delete" in their name are invalid parameter -- reject.

Exit codes: 0 = pass, 1 = validation failure(s), 2 = usage error.
"""
from __future__ import annotations

import argparse
import json
import re
import sys
from pathlib import Path

if sys.version_info < (3, 11):
    try:
        import tomli as tomllib  # type: ignore[import]
    except ImportError:
        print("ERROR: Python ≥ 3.11 required (tomllib stdlib) or install tomli.", file=sys.stderr)
        sys.exit(2)
else:
    import tomllib

ALLOWED_TOP_KEYS: frozenset[str] = frozenset({"kargs", "match-architectures"})

KNOWN_ARCHS: frozenset[str] = frozenset({
    "x86_64", "aarch64", "riscv64", "ppc64le", "s390x", "arm",
})

SECTION_HEADER_RE = re.compile(r"^\s*\[")


def _github_error(path: Path, line: int | None, msg: str) -> None:
    loc = f"file={path}" + (f",line={line}" if line is not None else "")
    print(f"::error {loc}::{msg}")


def _github_warning(path: Path, line: int | None, msg: str) -> None:
    loc = f"file={path}" + (f",line={line}" if line is not None else "")
    print(f"::warning {loc}::{msg}")


def validate_file(path: Path, *, github: bool = False, results: list[dict]) -> bool:
    ok = True
    issues: list[dict] = []

    raw = path.read_text(encoding="utf-8")
    lines = raw.splitlines()

    for lineno, text in enumerate(lines, start=1):
        if SECTION_HEADER_RE.match(text) and not text.strip().startswith("#"):
            msg = "[section] header found -- bootc forbids table headers in kargs.d"
            issues.append({"line": lineno, "msg": msg, "level": "error"})
            ok = False

    try:
        data = tomllib.loads(raw)
    except Exception as exc:
        msg = f"TOML parse error: {exc}"
        issues.append({"line": None, "msg": msg, "level": "error"})
        results.append({"path": str(path), "ok": False, "issues": issues})
        _emit(path, issues, github=github)
        return False

    for key in data:
        if key not in ALLOWED_TOP_KEYS:
            if "delete" in key.lower():
                msg = (
                    f"'{key}' is an invalid parameter -- bootc has no delete mechanism "
                    "in kargs.d drop-ins. Remove it."
                )
            else:
                msg = f"Unknown top-level key '{key}'. Only 'kargs' and 'match-architectures' are allowed."
            issues.append({"line": None, "msg": msg, "level": "error"})
            ok = False

    if "kargs" not in data:
        issues.append({"line": None, "msg": "Missing required 'kargs' key.", "level": "error"})
        ok = False
    else:
        kargs = data["kargs"]
        if not isinstance(kargs, list):
            issues.append({"line": None, "msg": f"'kargs' must be a list, got {type(kargs).__name__}.", "level": "error"})
            ok = False
        else:
            for i, entry in enumerate(kargs):
                if not isinstance(entry, str):
                    issues.append({
                        "line": None,
                        "msg": f"kargs[{i}] is {type(entry).__name__}, expected string.",
                        "level": "error",
                    })
                    ok = False
                elif " " in entry and not entry.startswith("console="):
                    issues.append({
                        "line": None,
                        "msg": (
                            f"kargs[{i}] '{entry}' contains a space. "
                            "Each kernel argument should be its own list entry."
                        ),
                        "level": "warning",
                    })

    if "match-architectures" in data:
        ma = data["match-architectures"]
        if not isinstance(ma, list):
            issues.append({
                "line": None,
                "msg": f"'match-architectures' must be a list, got {type(ma).__name__}.",
                "level": "error",
            })
            ok = False
        else:
            for arch in ma:
                if not isinstance(arch, str):
                    issues.append({"line": None, "msg": f"match-architectures entry {arch!r} is not a string.", "level": "error"})
                    ok = False
                elif arch not in KNOWN_ARCHS:
                    issues.append({
                        "line": None,
                        "msg": f"match-architectures: '{arch}' is not a known Rust target_arch value ({', '.join(sorted(KNOWN_ARCHS))}).",
                        "level": "warning",
                    })

    _emit(path, issues, github=github)
    results.append({"path": str(path), "ok": ok, "issues": issues})
    return ok


def _emit(path: Path, issues: list[dict], *, github: bool) -> None:
    for issue in issues:
        level = issue["level"]
        lineno = issue.get("line")
        msg = issue["msg"]
        if github:
            if level == "error":
                _github_error(path, lineno, msg)
            else:
                _github_warning(path, lineno, msg)
        else:
            loc = f":{lineno}" if lineno is not None else ""
            prefix = "ERROR" if level == "error" else "WARN "
            print(f"  {prefix}  {path}{loc}: {msg}")


def collect_files(dirs: list[Path]) -> list[Path]:
    files: list[Path] = []
    for d in dirs:
        if d.is_dir():
            files.extend(sorted(d.glob("*.toml")))
    return files


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description="Validate 'MiOS' kargs.d TOML files.")
    parser.add_argument("paths", nargs="*", help="Explicit .toml files or directories.")
    parser.add_argument("--github", action="store_true", help="Emit GitHub Actions annotation format.")
    parser.add_argument("--json", dest="json_out", action="store_true", help="Emit JSON report to stdout.")
    args = parser.parse_args(argv)

    if args.paths:
        candidates: list[Path] = []
        for p in args.paths:
            pp = Path(p)
            if pp.is_dir():
                candidates.extend(sorted(pp.glob("*.toml")))
            elif pp.suffix == ".toml":
                candidates.append(pp)
    else:
        repo_root = Path(__file__).parent.parent
        default_dirs = [
            repo_root / "kargs.d",
            repo_root / "system_files" / "usr" / "lib" / "bootc" / "kargs.d",
        ]
        candidates = collect_files(default_dirs)

    if not candidates:
        print("No .toml files found to validate.", file=sys.stderr)
        return 0

    results: list[dict] = []
    all_ok = True

    for f in candidates:
        if not args.github and not args.json_out:
            print(f"Checking {f} ...")
        passed = validate_file(f, github=args.github, results=results)
        if not passed:
            all_ok = False

    if args.json_out:
        print(json.dumps({"files": len(results), "pass": all_ok, "results": results}, indent=2))
    elif not args.github:
        passed_n = sum(1 for r in results if r["ok"])
        failed_n = len(results) - passed_n
        print(f"\n{passed_n}/{len(results)} files passed" + (f", {failed_n} failed" if failed_n else "."))

    return 0 if all_ok else 1


if __name__ == "__main__":
    sys.exit(main())

# automation/lib/globals.ps1
#
# PowerShell sibling of automation/lib/globals.sh. Single registry for
# MiOS-wide constants (VERSION, USERS, IMAGES, PORTS, URLS, REPOS).
# Dot-source from any PowerShell entry point:
#
#     . (Join-Path $PSScriptRoot 'automation/lib/globals.ps1')
#
# Variables land in the caller's $script: scope (PowerShell scoping
# rules: dot-sourced scripts run in the caller's scope, so everything
# below is visible to the caller without further ceremony). Override
# any constant with an environment variable BEFORE dot-sourcing -- e.g.
# `$env:MIOS_VERSION = '0.3.0-rc1'; . globals.ps1`.

# ── VERSION ──────────────────────────────────────────────────────────
function Resolve-MiosVersion {
    if ($env:MIOS_VERSION) { return ([string]$env:MIOS_VERSION).Trim() }
    foreach ($p in @(
        '/ctx/VERSION',
        '/usr/share/mios/VERSION',
        (Join-Path $PSScriptRoot '..\..\VERSION')
    )) {
        if ($p -and (Test-Path $p)) {
            $v = (Get-Content $p -EA SilentlyContinue | Out-String).Trim()
            if ($v) { return $v }
        }
    }
    return '0.2.4'
}
$script:MIOS_VERSION = Resolve-MiosVersion

# ── USERS / GROUPS ───────────────────────────────────────────────────
$script:MIOS_USER         = if ($env:MIOS_USER)         { $env:MIOS_USER }         else { 'mios' }
$script:MIOS_GROUP        = if ($env:MIOS_GROUP)        { $env:MIOS_GROUP }        else { 'mios' }
$script:MIOS_UID          = if ($env:MIOS_UID)          { [int]$env:MIOS_UID }     else { 1000 }
$script:MIOS_GID          = if ($env:MIOS_GID)          { [int]$env:MIOS_GID }     else { 1000 }

$script:MIOS_FORGE_USER   = if ($env:MIOS_FORGE_USER)   { $env:MIOS_FORGE_USER }   else { 'mios-forge' }
$script:MIOS_FORGE_UID    = if ($env:MIOS_FORGE_UID)    { [int]$env:MIOS_FORGE_UID } else { 816 }
$script:MIOS_FORGE_GID    = if ($env:MIOS_FORGE_GID)    { [int]$env:MIOS_FORGE_GID } else { 816 }

$script:MIOS_AI_USER      = if ($env:MIOS_AI_USER)      { $env:MIOS_AI_USER }      else { 'mios-ai' }
$script:MIOS_AI_UID       = if ($env:MIOS_AI_UID)       { [int]$env:MIOS_AI_UID }  else { 817 }
$script:MIOS_AI_GID       = if ($env:MIOS_AI_GID)       { [int]$env:MIOS_AI_GID }  else { 817 }

$script:MIOS_OLLAMA_USER  = if ($env:MIOS_OLLAMA_USER)  { $env:MIOS_OLLAMA_USER }  else { 'mios-ollama' }
$script:MIOS_OLLAMA_UID   = if ($env:MIOS_OLLAMA_UID)   { [int]$env:MIOS_OLLAMA_UID } else { 818 }
$script:MIOS_OLLAMA_GID   = if ($env:MIOS_OLLAMA_GID)   { [int]$env:MIOS_OLLAMA_GID } else { 818 }

$script:MIOS_CEPH_USER    = if ($env:MIOS_CEPH_USER)    { $env:MIOS_CEPH_USER }    else { 'mios-ceph' }
$script:MIOS_CEPH_UID     = if ($env:MIOS_CEPH_UID)     { [int]$env:MIOS_CEPH_UID }  else { 819 }
$script:MIOS_CEPH_GID     = if ($env:MIOS_CEPH_GID)     { [int]$env:MIOS_CEPH_GID }  else { 819 }

$script:MIOS_SUBUID_START = if ($env:MIOS_SUBUID_START) { [int]$env:MIOS_SUBUID_START } else { 100000 }
$script:MIOS_SUBUID_COUNT = if ($env:MIOS_SUBUID_COUNT) { [int]$env:MIOS_SUBUID_COUNT } else { 65536 }

# ── IMAGES ───────────────────────────────────────────────────────────
$script:MIOS_IMAGE_NAME   = if ($env:MIOS_IMAGE_NAME)   { $env:MIOS_IMAGE_NAME }   else { 'ghcr.io/mios-dev/mios' }
$script:MIOS_IMAGE_TAG    = if ($env:MIOS_IMAGE_TAG)    { $env:MIOS_IMAGE_TAG }    else { 'latest' }
$script:MIOS_IMAGE_REF    = if ($env:MIOS_IMAGE_REF)    { $env:MIOS_IMAGE_REF }    else { "$($script:MIOS_IMAGE_NAME):$($script:MIOS_IMAGE_TAG)" }
$script:MIOS_LOCAL_IMAGE  = if ($env:MIOS_LOCAL_IMAGE)  { $env:MIOS_LOCAL_IMAGE }  else { 'localhost/mios:latest' }
$script:MIOS_BASE_IMAGE   = if ($env:MIOS_BASE_IMAGE)   { $env:MIOS_BASE_IMAGE }   else { 'ghcr.io/ublue-os/ucore-hci:stable-nvidia' }
$script:MIOS_BIB_IMAGE    = if ($env:MIOS_BIB_IMAGE)    { $env:MIOS_BIB_IMAGE }    else { 'quay.io/centos-bootc/bootc-image-builder:latest' }

# ── PORTS ────────────────────────────────────────────────────────────
$script:MIOS_PORT_SSH           = if ($env:MIOS_PORT_SSH)           { [int]$env:MIOS_PORT_SSH }           else { 22 }
$script:MIOS_PORT_FORGE_HTTP    = if ($env:MIOS_PORT_FORGE_HTTP)    { [int]$env:MIOS_PORT_FORGE_HTTP }    else { 3000 }
$script:MIOS_PORT_FORGE_SSH     = if ($env:MIOS_PORT_FORGE_SSH)     { [int]$env:MIOS_PORT_FORGE_SSH }     else { 2222 }
$script:MIOS_PORT_LOCALAI       = if ($env:MIOS_PORT_LOCALAI)       { [int]$env:MIOS_PORT_LOCALAI }       else { 8080 }
$script:MIOS_PORT_COCKPIT       = if ($env:MIOS_PORT_COCKPIT)       { [int]$env:MIOS_PORT_COCKPIT }       else { 9090 }
$script:MIOS_PORT_OLLAMA        = if ($env:MIOS_PORT_OLLAMA)        { [int]$env:MIOS_PORT_OLLAMA }        else { 11434 }
$script:MIOS_PORT_COCKPIT_LINK  = if ($env:MIOS_PORT_COCKPIT_LINK)  { [int]$env:MIOS_PORT_COCKPIT_LINK }  else { 19090 }

# ── URLS ─────────────────────────────────────────────────────────────
$script:MIOS_AI_ENDPOINT  = if ($env:MIOS_AI_ENDPOINT)  { $env:MIOS_AI_ENDPOINT }  else { "http://localhost:$($script:MIOS_PORT_LOCALAI)/v1" }
$script:MIOS_FORGE_URL    = if ($env:MIOS_FORGE_URL)    { $env:MIOS_FORGE_URL }    else { "http://localhost:$($script:MIOS_PORT_FORGE_HTTP)" }
$script:MIOS_COCKPIT_URL  = if ($env:MIOS_COCKPIT_URL)  { $env:MIOS_COCKPIT_URL }  else { "https://localhost:$($script:MIOS_PORT_COCKPIT)" }
$script:MIOS_OLLAMA_URL   = if ($env:MIOS_OLLAMA_URL)   { $env:MIOS_OLLAMA_URL }   else { "http://localhost:$($script:MIOS_PORT_OLLAMA)" }

# ── REPOS ────────────────────────────────────────────────────────────
$script:MIOS_REPO_URL           = if ($env:MIOS_REPO_URL)           { $env:MIOS_REPO_URL }           else { 'https://github.com/mios-dev/mios.git' }
$script:MIOS_BOOTSTRAP_REPO_URL = if ($env:MIOS_BOOTSTRAP_REPO_URL) { $env:MIOS_BOOTSTRAP_REPO_URL } else { 'https://github.com/mios-dev/mios-bootstrap.git' }
$script:MIOS_LOCAL_FORGE_REPO   = if ($env:MIOS_LOCAL_FORGE_REPO)   { $env:MIOS_LOCAL_FORGE_REPO }   else { "http://localhost:$($script:MIOS_PORT_FORGE_HTTP)/mios/mios.git" }

# ── PATHS / DIRECTORIES ──────────────────────────────────────────────
# Vendor (deployed image)
$script:MIOS_USR_DIR                    = '/usr/lib/mios'
$script:MIOS_LIBEXEC_DIR                = '/usr/libexec/mios'
$script:MIOS_SHARE_DIR                  = '/usr/share/mios'
$script:MIOS_SHARE_AI_DIR               = "$($script:MIOS_SHARE_DIR)/ai"
$script:MIOS_SHARE_DISTROBOX_DIR        = "$($script:MIOS_SHARE_DIR)/distrobox"
$script:MIOS_SHARE_BRANDING_DIR         = "$($script:MIOS_SHARE_DIR)/branding"
$script:MIOS_SHARE_FASTFETCH_DIR        = "$($script:MIOS_SHARE_DIR)/fastfetch"
$script:MIOS_SHARE_KB_DIR               = "$($script:MIOS_SHARE_DIR)/kb"
$script:MIOS_SHARE_CONFIGURATOR_DIR     = "$($script:MIOS_SHARE_DIR)/configurator"
$script:MIOS_SHARE_K3S_MANIFESTS_DIR    = "$($script:MIOS_SHARE_DIR)/k3s-manifests"
# Admin overrides
$script:MIOS_ETC_DIR                    = '/etc/mios'
$script:MIOS_ETC_AI_DIR                 = "$($script:MIOS_ETC_DIR)/ai"
$script:MIOS_ETC_FORGE_DIR              = "$($script:MIOS_ETC_DIR)/forge"
$script:MIOS_ETC_ENVD_DIR               = "$($script:MIOS_ETC_DIR)/env.d"
# Runtime mutable
$script:MIOS_VAR_DIR                    = '/var/lib/mios'
$script:MIOS_VAR_AI_DIR                 = "$($script:MIOS_VAR_DIR)/ai"
$script:MIOS_VAR_MCP_DIR                = "$($script:MIOS_VAR_DIR)/mcp"
$script:MIOS_VAR_BACKUPS_DIR            = "$($script:MIOS_VAR_DIR)/backups"
$script:MIOS_VAR_CACHE_DIR              = "$($script:MIOS_VAR_DIR)/cache"
# LocalAI bind targets
$script:MIOS_SRV_AI_DIR                 = '/srv/ai'
$script:MIOS_SRV_AI_MODELS_DIR          = "$($script:MIOS_SRV_AI_DIR)/models"
$script:MIOS_SRV_AI_OUTPUTS_DIR         = "$($script:MIOS_SRV_AI_DIR)/outputs"
$script:MIOS_SRV_AI_COLLECTIONS_DIR     = "$($script:MIOS_SRV_AI_DIR)/collections"
$script:MIOS_SRV_AI_MCP_DIR             = "$($script:MIOS_SRV_AI_DIR)/mcp"
# Ollama
$script:MIOS_OLLAMA_RUNTIME_DIR         = '/var/lib/ollama/models'
$script:MIOS_OLLAMA_SEED_DIR            = '/usr/share/ollama/models'
# Windows-side dev paths
$script:MIOS_WIN_APPDATA_DIR            = if ($env:APPDATA)      { Join-Path $env:APPDATA 'MiOS' }      else { $null }
$script:MIOS_WIN_DOCS_DIR               = if ($env:USERPROFILE)  { Join-Path $env:USERPROFILE 'Documents\MiOS' } else { $null }
$script:MIOS_WIN_REPO_DIR               = if ($env:LOCALAPPDATA) { Join-Path $env:LOCALAPPDATA 'MiOS\repo' }     else { $null }

# ── FILES ────────────────────────────────────────────────────────────
# mios.toml chain (vendor < host < user)
$script:MIOS_TOML_VENDOR        = "$($script:MIOS_SHARE_DIR)/mios.toml"
$script:MIOS_TOML_HOST          = "$($script:MIOS_ETC_DIR)/mios.toml"
$script:MIOS_TOML_USER          = if ($env:HOME) { "$env:HOME/.config/mios/mios.toml" } else { '~/.config/mios/mios.toml' }
$script:MIOS_INSTALL_ENV        = "$($script:MIOS_ETC_DIR)/install.env"
$script:MIOS_FIRSTBOOT_SENTINEL = "$($script:MIOS_VAR_DIR)/.wsl-firstboot-done"
$script:MIOS_OLLAMA_SENTINEL    = "$($script:MIOS_VAR_DIR)/.ollama-firstboot-done"
$script:MIOS_AICHAT_DISTROBOX_INI    = "$($script:MIOS_SHARE_DISTROBOX_DIR)/aichat/distrobox.ini"
$script:MIOS_AICHAT_CONFIG_DEFAULT   = "$($script:MIOS_SHARE_DISTROBOX_DIR)/aichat/config.yaml"
$script:MIOS_AICHAT_USER_CONFIG      = if ($env:HOME) { "$env:HOME/.config/aichat/config.yaml" } else { '~/.config/aichat/config.yaml' }
$script:MIOS_AI_SYSTEM_PROMPT        = "$($script:MIOS_SHARE_AI_DIR)/system.md"
$script:MIOS_MCP_REGISTRY            = "$($script:MIOS_SHARE_AI_DIR)/v1/mcp.json"
$script:MIOS_BUILD_ENV_FILE          = if ($env:HOME) { "$env:HOME/.config/mios/mios-build.env" } else { '~/.config/mios/mios-build.env' }

# ── SYSTEMD UNITS ────────────────────────────────────────────────────
$script:MIOS_UNIT_AI                = 'mios-ai.service'
$script:MIOS_UNIT_FORGE             = 'mios-forge.service'
$script:MIOS_UNIT_FORGE_RUNNER      = 'mios-forgejo-runner.service'
$script:MIOS_UNIT_OLLAMA            = 'ollama.service'
$script:MIOS_UNIT_CEPH              = 'mios-ceph.service'
$script:MIOS_UNIT_K3S               = 'mios-k3s.service'
$script:MIOS_UNIT_AICHAT_BUILD      = 'mios-aichat-build.service'
$script:MIOS_UNIT_AICHAT_IMAGE      = 'mios-aichat-image.service'
$script:MIOS_UNIT_COCKPIT_LINK      = 'mios-cockpit-link.service'
$script:MIOS_UNIT_FIRSTBOOT_TARGET  = 'mios-firstboot.target'
$script:MIOS_UNIT_OLLAMA_FIRSTBOOT  = 'mios-ollama-firstboot.service'
$script:MIOS_UNIT_WSL_FIRSTBOOT     = 'mios-wsl-firstboot.service'
$script:MIOS_UNIT_USER_SESSION      = "user@$($script:MIOS_UID).service"

# ── CONTAINERS / DISTROBOX ───────────────────────────────────────────
$script:MIOS_DISTROBOX_AICHAT           = 'mios-aichat'
$script:MIOS_CONTAINER_AICHAT_IMAGE     = 'localhost/mios/aichat:latest'
$script:MIOS_CONTAINER_FORGE_IMAGE      = 'codeberg.org/forgejo/forgejo:12'
$script:MIOS_CONTAINER_LOCALAI_IMAGE    = 'docker.io/localai/localai:latest'
$script:MIOS_CONTAINER_OLLAMA_IMAGE     = 'docker.io/ollama/ollama:latest'

# ── COLOR PALETTE ────────────────────────────────────────────────────
# Hokusai + operator-neutrals palette. Vendor defaults; resolved from
# mios.toml [colors] at runtime by tools/lib/userenv.sh (operator
# overrides win). The configurator HTML and other consumers reference
# these by name. Override any single token via $env:MIOS_COLOR_*.
$script:MIOS_COLOR_BG       = if ($env:MIOS_COLOR_BG)       { $env:MIOS_COLOR_BG }       else { '#282262' }
$script:MIOS_COLOR_FG       = if ($env:MIOS_COLOR_FG)       { $env:MIOS_COLOR_FG }       else { '#E7DFD3' }
$script:MIOS_COLOR_ACCENT   = if ($env:MIOS_COLOR_ACCENT)   { $env:MIOS_COLOR_ACCENT }   else { '#1A407F' }
$script:MIOS_COLOR_CURSOR   = if ($env:MIOS_COLOR_CURSOR)   { $env:MIOS_COLOR_CURSOR }   else { '#F35C15' }
$script:MIOS_COLOR_SUCCESS  = if ($env:MIOS_COLOR_SUCCESS)  { $env:MIOS_COLOR_SUCCESS }  else { '#3E7765' }
$script:MIOS_COLOR_WARNING  = if ($env:MIOS_COLOR_WARNING)  { $env:MIOS_COLOR_WARNING }  else { '#F35C15' }
$script:MIOS_COLOR_ERROR    = if ($env:MIOS_COLOR_ERROR)    { $env:MIOS_COLOR_ERROR }    else { '#DC271B' }
$script:MIOS_COLOR_INFO     = if ($env:MIOS_COLOR_INFO)     { $env:MIOS_COLOR_INFO }     else { '#1A407F' }
$script:MIOS_COLOR_MUTED    = if ($env:MIOS_COLOR_MUTED)    { $env:MIOS_COLOR_MUTED }    else { '#948E8E' }
$script:MIOS_COLOR_SUBTLE   = if ($env:MIOS_COLOR_SUBTLE)   { $env:MIOS_COLOR_SUBTLE }   else { '#B7C9D7' }
$script:MIOS_COLOR_EARTH    = if ($env:MIOS_COLOR_EARTH)    { $env:MIOS_COLOR_EARTH }    else { '#734F39' }
$script:MIOS_COLOR_SILVER   = if ($env:MIOS_COLOR_SILVER)   { $env:MIOS_COLOR_SILVER }   else { '#E0E0E0' }
